+        if let Some(close) = cursor.rfind('}') {
+            if close > open {
+                let slice = &cursor[open..=close];
+                if let Ok(v) = serde_json::from_str(slice) {
+                    return Some(v);
+                }
+            }
+        }
+        // Try the next opening brace if this one didn't lead to valid JSON
